// And groups predicates with the AND operator between them.
func And(predicates ...predicate.DownloadRecord) predicate.DownloadRecord {
	return predicate.DownloadRecord(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.DownloadRecord) predicate.DownloadRecord {
	return predicate.DownloadRecord(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.DownloadRecord) predicate.DownloadRecord {
	return predicate.DownloadRecord(sql.NotPredicates(p))
}
